class Solution:
    def numsSameConsecDiff(self, n: int, k: int) -> List[int]:
        if n == 1:
            return [i for i in range(10)]
        res = []
        for i in range(10):
            if i == 0:
                self.dfs(res, i, n - 1, k)
            else:
                self.dfs(res, i, n - 1, k)
                if i + k <= 9:
                    self.dfs(res, i + k, n - 1, k)
        return res

    def dfs(self, res, num, n, k):
        if n == 0:
            res.append(num)
        else:
            if num % 10 + k <= 9:
                self.dfs(res, num * 10 + num % 10 + k, n - 1, k)
            if k != 0 and num % 10 - k >= 0:
                self.dfs(res, num * 10 + num % 10 - k, n - 1, k)
